"use client";

import {
  type HTMLAttributes,
  type MouseEvent,
  type ReactNode,
  type Ref,
  type RefObject,
  type SyntheticEvent,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { useFocusTrap } from "@/hooks/use-focus-trap";
import { usePresence } from "@/hooks/use-presence";
import { composeRefs } from "@/lib/compose-refs";

export interface DialogShellProps extends HTMLAttributes<HTMLDialogElement> {
  open: boolean;
  onBackdropClick?: (e: MouseEvent<HTMLDialogElement>) => void;
  onCancel?: (e: SyntheticEvent<HTMLDialogElement>) => void;
  onBeforeShowModal?: (ownerDocument: Document) => void;
  onAfterShowModal?: () => void;
  onClose?: () => void;
  children: ReactNode;
  dialogRef?: Ref<HTMLDialogElement>;
  initialFocus?: RefObject<HTMLElement | null>;
}

// Module-level stack of currently mounted, open DialogShell elements. Only the
// topmost shell runs its focus trap so peer/stacked dialogs do not fight over
// focus via competing focusin listeners on ownerDocument. Subscribers are
// notified after every push/pop with the new top element; each shell updates
// its local isTopShell state in response.
const openShellStack: HTMLElement[] = [];
const shellStackSubscribers = new Set<(top: HTMLElement | null) => void>();

function notifyShellStack(): void {
  const top = openShellStack.at(-1) ?? null;
  for (const cb of shellStackSubscribers) cb(top);
}

function pushShell(element: HTMLElement): void {
  openShellStack.push(element);
  notifyShellStack();
}

function popShell(element: HTMLElement): void {
  const index = openShellStack.lastIndexOf(element);
  if (index >= 0) openShellStack.splice(index, 1);
  notifyShellStack();
}

function isClickOutsideDialogRect(
  event: MouseEvent<HTMLDialogElement>,
  dialog: HTMLDialogElement,
): boolean {
  const rect = dialog.getBoundingClientRect();
  return (
    event.clientX < rect.left ||
    event.clientX > rect.right ||
    event.clientY < rect.top ||
    event.clientY > rect.bottom
  );
}

export function DialogShell({
  open,
  onBackdropClick,
  onCancel,
  onBeforeShowModal,
  onAfterShowModal,
  onClose,
  children,
  className,
  dialogRef: externalDialogRef,
  initialFocus,
  onClick,
  onAnimationEnd: externalOnAnimationEnd,
  ...props
}: DialogShellProps) {
  const shellRef = useRef<HTMLElement | null>(null);
  // usePresence's native animationend/animationcancel listener owns the
  // exit-complete path; do not also wire the returned React handler here or
  // onClose would fire twice on the non-portaled <dialog>.
  const { present } = usePresence({
    open,
    ref: shellRef,
    onExitComplete: () => {
      const element = shellRef.current;
      if (element instanceof HTMLDialogElement && element.open) {
        element.close();
      }
      onClose?.();
    },
  });

  // DialogContent owns focus restoration via useFocusRestore, so this trap is
  // configured with restoreFocus: false.
  const trapActive = open && present;

  // When dialogs stack (peer Dialog defaultOpen or programmatically opened
  // dialog-in-dialog), only the topmost shell's trap stays enabled. Outer
  // traps go dormant so their ownerDocument-level focusin listeners do not
  // fight the inner trap. isTopShell defaults to false so the first-render
  // useFocusTrap effect is a no-op; the layout effect then pushes onto the
  // stack and notifies all subscribers, and the resulting setState triggers a
  // follow-up render where exactly one shell activates its trap.
  const [isTopShell, setIsTopShell] = useState(false);
  useLayoutEffect(() => {
    if (!trapActive) return;
    const element = shellRef.current;
    if (!element) return;
    const updateTop = (top: HTMLElement | null) => setIsTopShell(top === element);
    shellStackSubscribers.add(updateTop);
    pushShell(element);
    return () => {
      shellStackSubscribers.delete(updateTop);
      popShell(element);
      setIsTopShell(false);
    };
  }, [trapActive]);

  useFocusTrap(shellRef, { enabled: trapActive && isTopShell, restoreFocus: false, initialFocus });

  useLayoutEffect(() => {
    const element = shellRef.current;
    if (!(element instanceof HTMLDialogElement)) return;
    if (open && present && !element.open) {
      onBeforeShowModal?.(element.ownerDocument);
      element.showModal();
      onAfterShowModal?.();
    }
  }, [onAfterShowModal, onBeforeShowModal, open, present]);

  if (!present) return null;

  const setShellRef = (node: HTMLElement | null) => {
    shellRef.current = node;
  };

  const dialogRef: Ref<HTMLDialogElement> = externalDialogRef
    ? composeRefs(setShellRef, externalDialogRef)
    : setShellRef;
  return (
    // biome-ignore lint/a11y/useKeyWithClickEvents: this onClick only detects backdrop (outside-rect) clicks to dismiss; keyboard dismissal is handled by the dialog's Escape behavior, so there is no keyboard equivalent for a backdrop click.
    <dialog
      {...props}
      ref={dialogRef}
      data-state={open ? "open" : "closed"}
      className={className}
      onClick={(e: MouseEvent<HTMLDialogElement>) => {
        onClick?.(e);
        const element = shellRef.current;
        if (
          element instanceof HTMLDialogElement &&
          e.target === element &&
          isClickOutsideDialogRect(e, element)
        ) {
          onBackdropClick?.(e);
        }
      }}
      onCancel={(e) => {
        onCancel?.(e);
        e.preventDefault();
      }}
      onAnimationEnd={externalOnAnimationEnd}
    >
      {children}
    </dialog>
  );
}

@layer base {
  dialog {
    --dialog-duration: 0.15s;
    padding: 0;
    border: none;
    background: transparent;
    overflow: visible;
  }
}

@layer components {
  dialog::backdrop {
    background: rgba(0, 0, 0, 0.6);
    -webkit-backdrop-filter: blur(4px);
    backdrop-filter: blur(4px);
  }

  dialog[data-state="open"]::backdrop {
    animation: backdrop-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"]::backdrop {
    animation: backdrop-out var(--dialog-duration) ease-in forwards;
  }

  dialog[data-state="open"] {
    animation: dialog-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"] {
    animation: dialog-out var(--dialog-duration) ease-in forwards;
  }

  /*
   * Scroll lock contract.
   * Native <dialog>.showModal() does not lock body scroll on its own. This
   * CSS-only lock activates whenever any descendant <dialog> exposes the
   * [open] attribute, and unlocks once every dialog closes.
   * scrollbar-gutter: stable avoids a horizontal layout shift when the
   * scrollbar is hidden under hidden-overflow.
   *
   * Limits (consumers in these cases must opt into a JS lock):
   *   - Custom scroll roots: only the <body> is locked. Apps that scroll on
   *     <html>, a wrapping element, or a scroll container handle their own
   *     scroll lock.
   *   - iOS Safari rubber-band: overflow:hidden on body does not prevent
   *     touchmove from scrolling the visual viewport.
   *   - :has() support floor: Chrome 105+, Safari 15.4+, Firefox 121+ — older
   *     engines do not get any body lock.
   */
  body:has(dialog[open]) {
    overflow: hidden;
    scrollbar-gutter: stable;
  }
}

@keyframes dialog-in {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes dialog-out {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.95);
  }
}

@keyframes backdrop-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes backdrop-out {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  dialog,
  dialog::backdrop {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the dialog animation declarations regardless of specificity. */
    animation: none !important;
  }
}

/*
 * DialogContent corner accents. Four corners total: dialog::before/::after =
 * top corners, dialog > .dlg-corners::before/::after = bottom corners. The
 * .dlg-corners span is only rendered when corners !== "none" so the
 * default path stays a plain CSS rectangle.
 */
@layer components {
  /*
   * Token defaults applied to each non-none corners value individually so
   * per-corner overrides have equal specificity and win via source order.
   */
  [data-slot="dialog-content"][data-corners="subtle"],
  [data-slot="dialog-content"][data-corners="standard"],
  [data-slot="dialog-content"][data-corners="bold"],
  [data-slot="dialog-content"][data-corners="outset"] {
    --dlg-corner-size: 18px;
    --dlg-corner-weight: 2px;
    --dlg-corner-color: var(--foreground);
    --dlg-corner-offset: 0px;
  }

  [data-slot="dialog-content"][data-corners="subtle"] {
    --dlg-corner-size: 12px;
    --dlg-corner-weight: 1.5px;
    --dlg-corner-color: var(--border);
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --dlg-corner-size: 28px;
    --dlg-corner-weight: 3px;
  }

  [data-slot="dialog-content"][data-corners="outset"] {
    --dlg-corner-offset: -3px;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before,
  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    content: "";
    position: absolute;
    width: var(--dlg-corner-size);
    height: var(--dlg-corner-size);
    border: 0 solid var(--dlg-corner-color);
    pointer-events: none;
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::before {
    top: var(--dlg-corner-offset);
    left: var(--dlg-corner-offset);
    border-top-width: var(--dlg-corner-weight);
    border-left-width: var(--dlg-corner-weight);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"])::after {
    top: var(--dlg-corner-offset);
    right: var(--dlg-corner-offset);
    border-top-width: var(--dlg-corner-weight);
    border-right-width: var(--dlg-corner-weight);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::before {
    bottom: var(--dlg-corner-offset);
    left: var(--dlg-corner-offset);
    border-bottom-width: var(--dlg-corner-weight);
    border-left-width: var(--dlg-corner-weight);
  }

  [data-slot="dialog-content"][data-corners]:not([data-corners="none"]) > .dlg-corners::after {
    bottom: var(--dlg-corner-offset);
    right: var(--dlg-corner-offset);
    border-bottom-width: var(--dlg-corner-weight);
    border-right-width: var(--dlg-corner-weight);
  }
}

/*
 * DialogTitle eyebrow meta tag typography tokens. Centralized here so consumers
 * can override the meta size/tracking globally without editing the primitive.
 */
@layer components {
  [data-slot="dialog-content"] {
    --dlg-title-meta-size: 11px;
    --dlg-title-meta-tracking: 0.08em;
  }
}

/*
 * Inset for the optional Dialog.CloseIcon (top-right). Default clears the
 * dialog edge; per-corner overrides push the button inward so it does not
 * collide with the corner accents.
 *   subtle  : 12px arms + 4px = 16px
 *   standard: 18px arms + 4px = 22px
 *   outset  : 18px arms (shifted -3px outside) + 4px ≈ 22px
 *   bold    : 28px arms + 4px = 32px
 */
@layer components {
  [data-slot="dialog-content"] {
    --dlg-close-btn-inset: 0.5rem;
  }

  [data-slot="dialog-content"][data-corners="subtle"] {
    --dlg-close-btn-inset: 16px;
  }

  [data-slot="dialog-content"][data-corners="standard"],
  [data-slot="dialog-content"][data-corners="outset"] {
    --dlg-close-btn-inset: 22px;
  }

  [data-slot="dialog-content"][data-corners="bold"] {
    --dlg-close-btn-inset: 32px;
  }
}
